def rod_cutting(n, price):
    price = [0] + price[:]
    dp = [0] * (n + 1)
    for length in range(1, n + 1):
        best = 0
        for cut in range(1, length + 1):
            val = price[cut] + dp[length - cut]
            if val > best:
                best = val
        dp[length] = best
    return dp[n]

